package com.arkeomag.pro; import android.content.*;import android.view.*;import android.graphics.*;import java.util.*;
public class Surface3DView extends View{Paint p=new Paint(1);int n=22;ArrayList<InterpolationEngine.P> pts=new ArrayList<>();float rot=0; public Surface3DView(Context c){super(c);} public void add(float v){float x=(pts.size()%n)/(float)(n-1),y=(pts.size()/n)/(float)(n-1); if(pts.size()>=n*n)pts.clear();pts.add(new InterpolationEngine.P(x,y,Math.min(1,v/45f)));invalidate();} protected void onDraw(Canvas c){int w=getWidth(),h=getHeight();p.setColor(Color.rgb(5,10,20));c.drawRect(0,0,w,h,p);float[][] g=InterpolationEngine.idw(pts,n);float scale=Math.min(w,h)*.55f, cx=w/2, cy=h*.62f;for(int j=0;j<n-1;j++)for(int i=0;i<n-1;i++){Path path=new Path();float[][] pp={{i,j},{i+1,j},{i+1,j+1},{i,j+1}};for(int k=0;k<4;k++){float x=(pp[k][0]/(n-1)-.5f),y=(pp[k][1]/(n-1)-.5f),z=g[(int)pp[k][0]][(int)pp[k][1]]*.55f;float sx=cx+(x-y)*scale*.8f;float sy=cy+(x+y)*scale*.38f-z*scale;if(k==0)path.moveTo(sx,sy);else path.lineTo(sx,sy);}path.close();p.setColor(Palette.color(g[i][j]));c.drawPath(path,p);}p.setColor(Color.WHITE);p.setTextSize(26);p.setTextAlign(Paint.Align.CENTER);c.drawText("3D SURFACE - IDW/KRIGING STYLE",cx,34,p);}}
